package com.example.lessondesign.bean; import okhttp3.*; import org.springframework.stereotype.Component; import java.io.File; import java.io.IOException; import java.util.concurrent.TimeUnit; @Component public class ApiClient { private final OkHttpClient client=new OkHttpClient().newBuilder().readTimeout(600,TimeUnit.SECONDS).build(); private String baseUrl="https://zwapi.xfyun.cn/api/ppt/v2"; public String create(String appId,String ts,String sig,File file) throws IOException { RequestBody body=new MultipartBody.Builder().setType(MultipartBody.FORM).addFormDataPart("file",file.getName(),RequestBody.create(MediaType.parse("multipart/form-data"),file)).addFormDataPart("fileName",file.getName()).build(); Request r=new Request.Builder().url(baseUrl+"/create").addHeader("appId",appId).addHeader("timestamp",ts).addHeader("signature",sig).post(body).build(); try(Response resp=client.newCall(r).execute()){ return resp.body().string(); } } public String checkProgress(String appId,String ts,String sig,String sid) throws IOException { Request r=new Request.Builder().url(baseUrl+"/progress?sid="+sid).addHeader("appId",appId).addHeader("timestamp",ts).addHeader("signature",sig).get().build(); try(Response resp=client.newCall(r).execute()){ return resp.body().string(); } } }